// Bias Detection Tool for Consultation Analysis
// Analyzes aggregated consultation data for various types of bias

const analysisData = JSON.parse(query);
const data = analysisData.data || analysisData;

// Initialize bias detection results
const biasResults = {
  biasDetected: false,
  biasScore: 0,
  biasDetails: [],
  demographicBias: { detected: false, score: 0, details: [] },
  geographicBias: { detected: false, score: 0, details: [] },
  stakeholderBias: { detected: false, score: 0, details: [] },
  temporalBias: { detected: false, score: 0, details: [] }
};

// Helper function to calculate distribution variance
function calculateVariance(distribution) {
  const values = Object.values(distribution);
  const mean = values.reduce((a, b) => a + b, 0) / values.length;
  const variance = values.reduce((sum, val) => sum + Math.pow(val - mean, 2), 0) / values.length;
  return Math.sqrt(variance) / mean; // Coefficient of variation
}

// 1. Demographic Bias Detection
const stakeholderTypes = {};
data.forEach(item => {
  const type = item.stakeholderType || 'unknown';
  stakeholderTypes[type] = (stakeholderTypes[type] || 0) + 1;
});

const totalSubmissions = data.length;
const stakeholderVariance = calculateVariance(stakeholderTypes);

if (stakeholderVariance > 0.7) {
  biasResults.demographicBias.detected = true;
  biasResults.demographicBias.score = Math.min(stakeholderVariance, 1);
  biasResults.demographicBias.details.push(
    `Significant stakeholder imbalance detected. Distribution: ${JSON.stringify(stakeholderTypes)}`
  );
}

// Check for over-representation
for (const [type, count] of Object.entries(stakeholderTypes)) {
  const percentage = (count / totalSubmissions) * 100;
  if (percentage > 60) {
    biasResults.demographicBias.detected = true;
    biasResults.demographicBias.score = Math.max(biasResults.demographicBias.score, percentage / 100);
    biasResults.demographicBias.details.push(
      `Over-representation of ${type}: ${percentage.toFixed(1)}% of submissions`
    );
  }
}

// 2. Geographic Bias Detection
const geographicScopes = {};
data.forEach(item => {
  const scope = item.geographicScope || 'unknown';
  geographicScopes[scope] = (geographicScopes[scope] || 0) + 1;
});

const geoVariance = calculateVariance(geographicScopes);

if (geoVariance > 0.6) {
  biasResults.geographicBias.detected = true;
  biasResults.geographicBias.score = Math.min(geoVariance, 1);
  biasResults.geographicBias.details.push(
    `Geographic representation imbalance. Distribution: ${JSON.stringify(geographicScopes)}`
  );
}

// 3. Stakeholder Representation Bias
const urgencyLevels = {};
data.forEach(item => {
  const urgency = item.urgencyLevel || 'unknown';
  urgencyLevels[urgency] = (urgencyLevels[urgency] || 0) + 1;
});

const criticalCount = urgencyLevels.critical || 0;
const criticalPercentage = (criticalCount / totalSubmissions) * 100;

if (criticalPercentage > 40) {
  biasResults.stakeholderBias.detected = true;
  biasResults.stakeholderBias.score = criticalPercentage / 100;
  biasResults.stakeholderBias.details.push(
    `High proportion of critical urgency submissions (${criticalPercentage.toFixed(1)}%) may indicate coordinated campaign or crisis response`
  );
}

// Check for evidence quality bias
const evidenceQuality = {};
data.forEach(item => {
  const quality = item.evidenceQuality || 'unknown';
  evidenceQuality[quality] = (evidenceQuality[quality] || 0) + 1;
});

const lowEvidencePercentage = ((evidenceQuality.low || 0) / totalSubmissions) * 100;
if (lowEvidencePercentage > 50) {
  biasResults.stakeholderBias.detected = true;
  biasResults.stakeholderBias.score = Math.max(biasResults.stakeholderBias.score, lowEvidencePercentage / 100);
  biasResults.stakeholderBias.details.push(
    `High proportion of low-evidence submissions (${lowEvidencePercentage.toFixed(1)}%)`
  );
}

// 4. Temporal Bias Detection (if submission dates available)
const submissionDates = data.filter(item => item.submissionDate).map(item => new Date(item.submissionDate));

if (submissionDates.length > 0) {
  submissionDates.sort((a, b) => a - b);
  const firstDate = submissionDates[0];
  const lastDate = submissionDates[submissionDates.length - 1];
  const totalDays = (lastDate - firstDate) / (1000 * 60 * 60 * 24);

  // Check for clustering (>50% of submissions in <20% of time period)
  const midpoint = new Date(firstDate.getTime() + (lastDate - firstDate) / 5);
  const earlySubmissions = submissionDates.filter(d => d <= midpoint).length;
  const earlyPercentage = (earlySubmissions / submissionDates.length) * 100;

  if (earlyPercentage > 50) {
    biasResults.temporalBias.detected = true;
    biasResults.temporalBias.score = earlyPercentage / 100;
    biasResults.temporalBias.details.push(
      `Temporal clustering detected: ${earlyPercentage.toFixed(1)}% of submissions in first 20% of consultation period`
    );
  }
}

// Calculate overall bias score (weighted average)
const weights = { demographic: 0.3, geographic: 0.25, stakeholder: 0.3, temporal: 0.15 };
biasResults.biasScore = 
  (biasResults.demographicBias.score * weights.demographic) +
  (biasResults.geographicBias.score * weights.geographic) +
  (biasResults.stakeholderBias.score * weights.stakeholder) +
  (biasResults.temporalBias.score * weights.temporal);

// Determine if bias is detected (threshold: 0.4)
biasResults.biasDetected = biasResults.biasScore > 0.4;

// Compile all bias details
if (biasResults.demographicBias.detected) {
  biasResults.biasDetails.push(...biasResults.demographicBias.details);
}
if (biasResults.geographicBias.detected) {
  biasResults.biasDetails.push(...biasResults.geographicBias.details);
}
if (biasResults.stakeholderBias.detected) {
  biasResults.biasDetails.push(...biasResults.stakeholderBias.details);
}
if (biasResults.temporalBias.detected) {
  biasResults.biasDetails.push(...biasResults.temporalBias.details);
}

if (!biasResults.biasDetected) {
  biasResults.biasDetails.push('No significant bias detected in consultation data');
}

// Return results as JSON string
return JSON.stringify(biasResults, null, 2);

// Parse the input query which should contain governance metadata
const metadata = typeof query === 'string' ? JSON.parse(query) : query;

// Generate a unique traceability record ID
const recordId = `trace-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

// Create comprehensive traceability record
const traceabilityRecord = {
  recordId: recordId,
  timestamp: new Date().toISOString(),
  recordType: 'consultation_analysis_governance',

  // Analysis metadata
  analysisMetadata: {
    totalSubmissions: metadata.totalSubmissions || 0,
    analysisDate: metadata.analysisDate || new Date().toISOString(),
    analysisAgent: 'Consultation Analysis Agent',
    governanceAgent: 'Decision Governance Agent'
  },

  // Decision points
  decisionPoints: {
    governanceDecision: metadata.governanceDecision || 'unknown',
    escalationLevel: metadata.escalationLevel || 'routine',
    escalationReason: metadata.escalationReason || 'N/A',
    biasDetected: metadata.biasDetected || false,
    biasScore: metadata.biasScore || 0,
    confidenceScore: metadata.confidenceScore || 0
  },

  // Data lineage
  dataLineage: {
    sourceNode: 'Fetch Consultation Data',
    processingNodes: [
      'Split Submissions',
      'Consultation Analysis Agent',
      'Aggregate Analysis Results',
      'Decision Governance Agent'
    ],
    outputDestination: 'Store Traceability Records',
    dataTransformations: [
      'Individual submission analysis',
      'Sentiment and theme extraction',
      'Aggregation of results',
      'Bias detection',
      'Governance decision'
    ]
  },

  // Governance actions
  governanceActions: {
    summaryGenerated: metadata.summaryGenerated || false,
    traceabilityRecordCreated: true,
    recommendedActions: metadata.recommendedActions || [],
    stakeholdersToNotify: metadata.stakeholdersToNotify || [],
    timelineForResponse: metadata.timelineForResponse || 'N/A',
    governanceNotes: metadata.governanceNotes || ''
  },

  // Audit trail
  auditTrail: {
    workflowExecutionId: $execution.id || 'unknown',
    workflowName: 'Public Consultation Analysis and Governance Coordination System',
    executionMode: $execution.mode || 'unknown',
    createdBy: 'system',
    recordStatus: 'active',
    retentionPeriod: '7_years',
    complianceFlags: {
      transparencyCompliant: true,
      accountabilityCompliant: true,
      dataProtectionCompliant: true
    }
  }
};

// Return the traceability record as a JSON string
return JSON.stringify(traceabilityRecord, null, 2);

// Summary Generation Tool
// Generates executive summaries, thematic summaries, and statistical summaries

const analysisData = JSON.parse(query);

// Extract key statistics
const totalSubmissions = analysisData.data ? analysisData.data.length : 0;
const sentimentCounts = {};
const urgencyCounts = {};
const stakeholderCounts = {};
const themeFrequency = {};

if (analysisData.data) {
  analysisData.data.forEach(item => {
    // Count sentiments
    const sentiment = item.sentiment || 'unknown';
    sentimentCounts[sentiment] = (sentimentCounts[sentiment] || 0) + 1;

    // Count urgency levels
    const urgency = item.urgencyLevel || 'unknown';
    urgencyCounts[urgency] = (urgencyCounts[urgency] || 0) + 1;

    // Count stakeholder types
    const stakeholder = item.stakeholderType || 'unknown';
    stakeholderCounts[stakeholder] = (stakeholderCounts[stakeholder] || 0) + 1;

    // Count themes
    if (item.keyThemes && Array.isArray(item.keyThemes)) {
      item.keyThemes.forEach(theme => {
        themeFrequency[theme] = (themeFrequency[theme] || 0) + 1;
      });
    }
  });
}

// Get top themes
const topThemes = Object.entries(themeFrequency)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([theme, count]) => `${theme} (${count} mentions)`);

// Calculate average policy relevance
let avgPolicyRelevance = 0;
if (analysisData.data && analysisData.data.length > 0) {
  const relevanceSum = analysisData.data.reduce((sum, item) => {
    return sum + (item.policyRelevance || 0);
  }, 0);
  avgPolicyRelevance = (relevanceSum / analysisData.data.length).toFixed(2);
}

// Generate executive summary
const executiveSummary = `
EXECUTIVE SUMMARY
=================

Total Submissions Analyzed: ${totalSubmissions}

SENTIMENT DISTRIBUTION:
${Object.entries(sentimentCounts).map(([k, v]) => `  - ${k}: ${v} (${((v/totalSubmissions)*100).toFixed(1)}%)`).join('\n')}

URGENCY LEVELS:
${Object.entries(urgencyCounts).map(([k, v]) => `  - ${k}: ${v} (${((v/totalSubmissions)*100).toFixed(1)}%)`).join('\n')}

STAKEHOLDER BREAKDOWN:
${Object.entries(stakeholderCounts).map(([k, v]) => `  - ${k}: ${v} (${((v/totalSubmissions)*100).toFixed(1)}%)`).join('\n')}

TOP THEMES:
${topThemes.map((theme, i) => `  ${i+1}. ${theme}`).join('\n')}

AVERAGE POLICY RELEVANCE: ${avgPolicyRelevance}/1.0

KEY INSIGHTS:
- ${urgencyCounts.critical || 0} submissions flagged as CRITICAL urgency
- ${urgencyCounts.high || 0} submissions flagged as HIGH urgency
- Dominant sentiment: ${Object.entries(sentimentCounts).sort((a,b) => b[1] - a[1])[0]?.[0] || 'N/A'}
- Primary stakeholder group: ${Object.entries(stakeholderCounts).sort((a,b) => b[1] - a[1])[0]?.[0] || 'N/A'}

This summary provides an objective overview of consultation submissions for governance coordination purposes only.
`;

return executiveSummary;

