// Consolidate and store traceability records for all escalation paths
// This creates a comprehensive audit trail for governance decisions

const items = $input.all();
const traceabilityRecords = [];

// Process each escalation path item
for (const item of items) {
  const record = {
    // Core identification
    recordId: `trace-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
    timestamp: new Date().toISOString(),

    // Escalation metadata
    escalationType: item.json.escalationType || 'unknown',
    escalationLevel: item.json.escalationLevel || 'routine',
    escalationReason: item.json.escalationReason || 'N/A',

    // Governance decision details
    governanceDecision: item.json.governanceDecision || 'N/A',
    confidenceScore: item.json.confidenceScore || 0,
    governanceNotes: item.json.governanceNotes || '',

    // Bias detection results
    biasDetected: item.json.biasDetected || false,
    biasScore: item.json.biasScore || 0,
    biasDetails: item.json.biasDetails || [],
    biasAlertFlag: item.json.biasAlertFlag || false,

    // Notification and action tracking
    notificationPriority: item.json.notificationPriority || 'routine',
    recipientGroup: item.json.recipientGroup || 'consultation_team',
    stakeholdersToNotify: item.json.stakeholdersToNotify || [],
    recommendedActions: item.json.recommendedActions || [],
    timelineForResponse: item.json.timelineForResponse || '7_days',

    // Summary and reporting
    summaryGenerated: item.json.summaryGenerated || false,
    traceabilityRecordCreated: true,

    // Audit trail metadata
    workflowExecutionId: $execution.id,
    workflowName: $workflow.name,
    nodeExecutionTime: new Date().toISOString(),

    // Full data snapshot for audit purposes
    fullDataSnapshot: item.json
  };

  traceabilityRecords.push(record);
}

// Prepare consolidated output
const consolidatedOutput = {
  totalRecords: traceabilityRecords.length,
  recordsCreated: new Date().toISOString(),
  executionId: $execution.id,
  workflowName: $workflow.name,
  traceabilityRecords: traceabilityRecords,

  // Summary statistics
  summary: {
    criticalEscalations: traceabilityRecords.filter(r => r.escalationType === 'critical').length,
    standardReports: traceabilityRecords.filter(r => r.escalationType === 'standard').length,
    routineUpdates: traceabilityRecords.filter(r => r.escalationType === 'routine').length,
    biasAlertsTriggered: traceabilityRecords.filter(r => r.biasAlertFlag === true).length,
    averageBiasScore: traceabilityRecords.reduce((sum, r) => sum + (r.biasScore || 0), 0) / traceabilityRecords.length,
    averageConfidenceScore: traceabilityRecords.reduce((sum, r) => sum + (r.confidenceScore || 0), 0) / traceabilityRecords.length
  },

  // Storage metadata
  storageUrl: $('Workflow Configuration').first().json.traceabilityStorageUrl || '<PLACEHOLDER>',
  storageStatus: 'pending_api_call',
  storageNote: 'Records prepared for storage. Implement HTTP Request to storage API endpoint.'
};

// Return consolidated traceability records
return [consolidatedOutput];
